#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

vec4 dbg=0.0;

//vec3 lightCol = { q10, q11, q12 };

vec3 main = texture( sampler_main, vUv );
main = -log( 1.0 - main* 0.8 );
main = min( main, 3.0 );


vec2 planetuvs = (vUv-0.5)*uAspect*1.0;
planetuvs = vec2( planetuvs.x * q8 - planetuvs.y * q9, planetuvs.x * q9 + planetuvs.y * q8 );
planetuvs += 0.5;
vec4 planet = texture( sampler_rand00, planetuvs );
vec4 planetOrig = planet;
planet *= (vRadius*q7);



vec3 uv_sphere;
uv_sphere.xy = (vUv - 0.5)*q1.xx*uAspect;
uv_sphere.z = sqrt( 1.0 - dot( uv_sphere.xy, uv_sphere.xy ) );

vec3 normal = uv_sphere;




//lightvectors
vec3 lightvec;
lightvec.xy = (vUvOriginal - vec2(q3,q4)) * uAspect.xy;
float distanceToLight = length( lightvec.xy );
lightvec.z = 0.15;
lightvec = normalize( lightvec );

vec3 lightvec2 = normalize( vec3( q6, 0.3, 0.2 ) );


normal.xy *= -1.0;
float normalLength = length( normal.xy );
normal /= normalLength;

vec3 redlight = dot( lightvec, normal );
redlight = clamp01( redlight );
redlight *= normalLength > 1.0 ? clamp01( (normalLength - 1.0)*0.5 ) : clamp01( normal.z * 2.0 );
redlight *= lightCol;


//light2----
vec3 sunamt = clamp01( dot( lightvec2, normal ) );

//ambientlight--
vec3 ambientlight = (normal.y*0.5+0.5) * vec3(0.4,0.7,1.0)*0.5;

//diffuse
vec3 diffuse = mix( ambientlight, lightCol2, sunamt );
diffuse *= 0.6;
diffuse += redlight;



//specular----------
vec3 viewVec = vec3( (vUv-0.5)*q1*uAspect, -0.5 );
viewVec = normalize( viewVec );

vec3 R = reflect( viewVec, normal );
R = normalize( R );

//main ref
vec3 specular = clamp01( dot( R, lightvec ) );


//inside ref
vec3 Ri = reflect( viewVec, normalize(normal * vec3(1.0,0.5,1.0)) );
vec3 speculari = clamp01( dot( Ri, lightvec ) );
//specular = max( specular, speculari );

specular = pow( specular, vec3( 1.0, 1.0, 1.0 )*28.0 );
specular = clamp01( specular * 2.0 - 1.0 );
specular *= lightCol * 2.0;

//spec sunlight
vec3 specsun = dot( R, lightvec2 );
specsun = pow( specsun, 38.0 );
specsun = clamp01( specsun * 1.5 );
specsun *= lightCol2 * 2.0;
specular += specsun;

ret = main * normal.z;
ret += diffuse;


ret += specular;


ret = mix( ret, planet, planet.a )-audioLowSmooth*0.5;
ret += planetOrig * planetOrig * 0.5;

vec3 lightSource = clamp01( 1.0 - distanceToLight*9.0 );
lightSource *= lightSource * lightCol * 4.0;
lightSource *= 3.0 - planetOrig.a * 2.0;
ret += lightSource;




ret = dbg.a == 1.0 ? dbg.rgb : ret; //debug output


//tonemapping
ret = 1.0 - exp( -ret * 1.0 );


//ret = planet;


  fragColor = ret;
}
